REQUIRED = {'case_id', 'metric', 'params', 'rerun_metric', 'seed', 'tolerance'}
REJECT = 'MARK_RUN_NONREPRODUCIBLE'

def assess(record: dict) -> str:
    absent = sorted(REQUIRED - record.keys())
    if absent:
        return "MISSING:" + ",".join(absent)
    contract_ok = not (abs(record["metric"] - record["rerun_metric"]) > record["tolerance"])
    return "PASS" if contract_ok else REJECT

